// Traffic-light badge that surfaces the automatic QA of the dub.
//
// Reads the `.dub-qa.json` sidecar generated by dubbing-generator after
// each `_DOBLADO.mkv`. Colour = global verdict (green/amber/red), text =
// predicted MOS when UTMOS ran, otherwise a short boundary-count hint.
// Clicking it opens a dialog with the per-boundary breakdown so the
// user can jump to the timestamps that sound off.
import { useState } from 'react'
import { AlertTriangle, CheckCircle2, Gauge, XCircle } from 'lucide-react'
import { Badge } from '@/components/ui/Badge'
import { Button } from '@/components/ui/button'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { cn } from '@/lib/utils'
import { useDubQa } from '../api/useDubQa'

function formatTs(ms) {
  if (ms == null) return '--:--'
  const total = Math.max(0, Math.round(ms / 1000))
  const m = Math.floor(total / 60)
  const s = total % 60
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`
}

function verdictStyles(level) {
  switch (level) {
    case 'red':
      return {
        badge: 'border-red-500/40 bg-red-500/15 text-red-400',
        Icon: XCircle,
      }
    case 'amber':
      return {
        badge: 'border-amber-500/40 bg-amber-500/15 text-amber-400',
        Icon: AlertTriangle,
      }
    default:
      return {
        badge: 'border-emerald-500/40 bg-emerald-500/15 text-emerald-400',
        Icon: CheckCircle2,
      }
  }
}

export default function DubQaBadge({ videoPath, enabled }) {
  const [open, setOpen] = useState(false)
  const { data, isLoading } = useDubQa(videoPath, { enabled })

  if (!enabled || isLoading || !data) return null

  const verdict = data.verdict || {}
  const level = verdict.level || 'green'
  const { badge, Icon } = verdictStyles(level)
  const mos = verdict.mos
  const hard = verdict.hard_cuts ?? 0
  const warn = verdict.warnings ?? 0

  const short = mos != null
    ? `MOS ${mos.toFixed(2)}`
    : hard > 0
      ? `${hard} cortes`
      : warn > 0
        ? `${warn} avisos`
        : 'OK'

  const issues = data.boundaries?.issues || []
  const problematic = issues.filter((b) => b.severity !== 'ok')

  return (
    <>
      <button
        type="button"
        onClick={() => setOpen(true)}
        title="Calidad automática del doblaje"
        className={cn(
          // Fixed height + align-middle + whitespace-nowrap keeps the
          // badge on a single line and vertically centred next to the
          // status icons in ChaptersTab. Without this it wrapped to
          // two lines ("MOS" / "2.21") and pushed the row up.
          'inline-flex h-6 shrink-0 items-center gap-1 whitespace-nowrap rounded-full border px-2 text-[11px] font-medium leading-none align-middle hover:opacity-90',
          badge,
        )}
      >
        <Icon className="h-3 w-3" />
        {short}
      </button>
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Gauge className="h-4 w-4" />
              QA del doblaje
            </DialogTitle>
          </DialogHeader>
          <QaSummary data={data} />
          <QaIssues issues={problematic} />
        </DialogContent>
      </Dialog>
    </>
  )
}

function QaSummary({ data }) {
  const verdict = data.verdict || {}
  const mos = verdict.mos
  const boundaries = data.boundaries || {}
  const total = boundaries.total_boundaries ?? 0

  return (
    <div className="grid grid-cols-3 gap-3 text-sm">
      <StatTile
        label="Veredicto"
        value={(verdict.level || '—').toUpperCase()}
        tone={verdict.level}
      />
      <StatTile
        label="MOS predicho"
        value={mos != null ? mos.toFixed(2) : '—'}
        hint={mos != null ? '1 malo · 5 natural' : 'UTMOS no disponible'}
      />
      <StatTile
        label="Transiciones"
        value={`${verdict.hard_cuts ?? 0} duras / ${verdict.warnings ?? 0} avisos`}
        hint={`${total} totales`}
      />
    </div>
  )
}

function StatTile({ label, value, hint, tone }) {
  const toneCls =
    tone === 'red'
      ? 'text-red-400'
      : tone === 'amber'
        ? 'text-amber-400'
        : tone === 'green'
          ? 'text-emerald-400'
          : 'text-zinc-100'
  return (
    <div className="rounded-lg border border-zinc-800 bg-zinc-900/60 px-3 py-2">
      <div className="text-[11px] uppercase tracking-wide text-zinc-500">{label}</div>
      <div className={cn('mt-1 text-lg font-semibold', toneCls)}>{value}</div>
      {hint && <div className="mt-0.5 text-[11px] text-zinc-500">{hint}</div>}
    </div>
  )
}

function QaIssues({ issues }) {
  if (!issues.length) {
    return (
      <p className="mt-3 text-sm text-zinc-500">
        Sin transiciones problemáticas. 🎧
      </p>
    )
  }
  return (
    <div className="mt-3 max-h-80 overflow-y-auto rounded-lg border border-zinc-800">
      <table className="w-full text-left text-xs">
        <thead className="sticky top-0 bg-zinc-900 text-zinc-400">
          <tr>
            <th className="px-3 py-2">Timestamp</th>
            <th className="px-3 py-2">Severidad</th>
            <th className="px-3 py-2">Gap</th>
            <th className="px-3 py-2">Motivos</th>
          </tr>
        </thead>
        <tbody>
          {issues.map((b) => (
            <tr
              key={b.index}
              className="border-t border-zinc-800/60 hover:bg-zinc-900/40"
            >
              <td className="px-3 py-1.5 font-mono">{formatTs(b.timestamp_ms)}</td>
              <td className="px-3 py-1.5">
                <Badge
                  variant="secondary"
                  className={cn(
                    b.severity === 'hard' && 'bg-red-500/15 text-red-400',
                    b.severity === 'warn' && 'bg-amber-500/15 text-amber-400',
                  )}
                >
                  {b.severity}
                </Badge>
              </td>
              <td className="px-3 py-1.5">{b.gap_ms} ms</td>
              <td className="px-3 py-1.5 text-zinc-300">
                {(b.reasons || []).join(' · ') || '—'}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
